    for &kw in CPP_RESERVED {
        if lower == kw.to_lowercase() {
            return Some("C++ reserved keyword");
        }
    }
    for &kw in QT_RESERVED {
        if lower == kw.to_lowercase() {
            return Some("Qt reserved identifier");
        }
    }
